WITH RECURSIVE tree_nodes AS (
    SELECT id FROM ${tableCode}
    WHERE ${deleteColumn} = '0' AND ${parentColumn} = #{nodeId}
    UNION ALL
    SELECT t.id FROM ${tableCode} t
    INNER JOIN tree_nodes tn ON t.${parentColumn} = tn.id
    WHERE t.${deleteColumn} = '0'
)
